import React, { useRef, useMemo, useEffect, useState } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { Float, Points, PointMaterial } from '@react-three/drei';
import * as THREE from 'three';

// Optimized floating shapes
function FloatingShapes() {
  const shapes = useMemo(() => {
    return Array.from({ length: 8 }, (_, i) => ({
      id: i,
      position: [
        (Math.random() - 0.5) * 15,
        (Math.random() - 0.5) * 8,
        (Math.random() - 0.5) * 8
      ],
      rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
      scale: Math.random() * 0.3 + 0.1,
      type: ['box', 'sphere', 'torus'][Math.floor(Math.random() * 3)]
    }));
  }, []);

  return (
    <>
      {shapes.map((shape) => (
        <Float
          key={shape.id}
          speed={Math.random() * 1.5 + 0.5}
          rotationIntensity={Math.random() * 0.3 + 0.2}
          floatIntensity={Math.random() * 1.5 + 0.5}
        >
          <mesh
            position={shape.position}
            rotation={shape.rotation}
            scale={shape.scale}
          >
            {shape.type === 'box' && <boxGeometry args={[1, 1, 1]} />}
            {shape.type === 'sphere' && <sphereGeometry args={[0.7, 16, 16]} />}
            {shape.type === 'torus' && <torusGeometry args={[0.7, 0.3, 8, 16]} />}

            <meshStandardMaterial
              color={shape.id % 3 === 0 ? '#3B82F6' : shape.id % 3 === 1 ? '#e50914' : '#1F2937'}
              metalness={0.8}
              roughness={0.2}
              emissive={shape.id % 3 === 0 ? '#3B82F6' : shape.id % 3 === 1 ? '#e50914' : '#1F2937'}
              emissiveIntensity={0.05}
            />
          </mesh>
        </Float>
      ))}
    </>
  );
}

// Optimized particle system
function ParticleField() {
  const points = useRef();

  const particles = useMemo(() => {
    const positions = new Float32Array(150 * 3);
    for (let i = 0; i < 150 * 3; i += 3) {
      positions[i] = (Math.random() - 0.5) * 20;
      positions[i + 1] = (Math.random() - 0.5) * 15;
      positions[i + 2] = (Math.random() - 0.5) * 15;
    }
    return positions;
  }, []);

  useFrame((state) => {
    if (points.current) {
      points.current.rotation.y = state.clock.elapsedTime * 0.05;
      points.current.rotation.x = state.clock.elapsedTime * 0.02;
    }
  });

  return (
    <Points ref={points} positions={particles} stride={3} frustumCulled={false}>
      <PointMaterial
        color="#3B82F6"
        size={0.03}
        transparent
        opacity={0.4}
        depthWrite={false}
      />
    </Points>
  );
}

// Main 3D Scene
function Scene() {
  return (
    <>
      <ambientLight intensity={0.2} />
      <directionalLight position={[10, 10, 5]} intensity={0.8} color="#ffffff" />
      <pointLight position={[-10, -10, -5]} intensity={0.3} color="#3B82F6" />
      <pointLight position={[10, -10, 5]} intensity={0.3} color="#e50914" />

      <FloatingShapes />
      <ParticleField />
    </>
  );
}

export default function ThreeBackground() {
  const [isClient, setIsClient] = useState(false);

  useEffect(() => {
    setIsClient(true);
  }, []);

  if (!isClient) {
    return (
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-gradient-to-br from-primary via-primary/90 to-secondary"></div>
      </div>
    );
  }

  return (
    <div className="absolute inset-0 z-0">
      <Canvas
        camera={{ position: [0, 0, 10], fov: 75 }}
        style={{ background: 'transparent' }}
        dpr={[1, 2]} // Optimize for different device pixel ratios
        performance={{ min: 0.5 }} // Performance optimization
      >
        <Scene />
      </Canvas>
    </div>
  );
}
